1	/** A live cell's position on the infinite grid, as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [0, -1], [1, -1],
6	  [-1,  0],          [1,  0],
7	  [-1,  1], [0,  1], [1,  1],
8	];
9	
10	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
11	
12	const neighborsOf = ([x, y]: Cell): Cell[] =>
13	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
14	
15	const countLiveNeighbors = (cell: Cell, liveSet: Set<string>): number =>
16	  neighborsOf(cell).filter((neighbor) => liveSet.has(cellKey(neighbor))).length;
17	
18	/**
19	 * Computes the live cells of the next generation of Conway's Game of Life
20	 * from the current set of live cells.
21	 */
22	export function nextGeneration(liveCells: Cell[]): Cell[] {
23	  const liveSet = new Set(liveCells.map(cellKey));
24	  const survivors = liveCells.filter((cell) => countLiveNeighbors(cell, liveSet) >= 2);
25	
26	  const candidateMap = new Map<string, Cell>();
27	  for (const live of liveCells) {
28	    for (const neighbor of neighborsOf(live)) {
29	      const key = cellKey(neighbor);
30	      if (!liveSet.has(key)) candidateMap.set(key, neighbor);
31	    }
32	  }
33	  const births: Cell[] = [];
34	  for (const candidate of candidateMap.values()) {
35	    if (countLiveNeighbors(candidate, liveSet) === 3) births.push(candidate);
36	  }
37	
38	  return [...survivors, ...births];
39	}
