const countLiveNeighbors = (cell: Cell, liveKeys: Set<string>): number =>
  neighborsOf(cell).filter((neighbor) => liveKeys.has(cellKey(neighbor))).length;

const deadNeighborsOf = (liveCells: Cell[], liveKeys: Set<string>): Cell[] => {
  const dead = new Map<string, Cell>();
  for (const live of liveCells) {
    for (const neighbor of neighborsOf(live)) {
      const key = cellKey(neighbor);
      if (!liveKeys.has(key)) dead.set(key, neighbor);
    }
  }
  return [...dead.values()];
};

/**
 * Computes the live cells of the next generation of Conway's Game of Life
 * from the current set of live cells.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const survivors = liveCells.filter((cell) => countLiveNeighbors(cell, liveKeys) >= 2);
  const births = deadNeighborsOf(liveCells, liveKeys)
    .filter((cell) => countLiveNeighbors(cell, liveKeys) === 3);
  return [...survivors, ...births];
}
